import { useState } from "react";
import { motion } from "framer-motion";
import { Users, ChevronDown, ChevronUp } from "lucide-react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import SocialExpandedContent, { SOCIAL_EXPANDED_FAQS } from "@/components/SocialExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 0 });
}


const FAQS = [
  { q: "How much should a freelance social media manager charge?", a: "Freelance social media managers typically charge $15-$25/hour for entry-level, $30-$60/hour mid-level, and $60-$150/hour for specialists. Package rates ($500-$3,000/month per client) are more common than hourly billing for ongoing management clients." },
  { q: "What's included in a social media management package?", a: "Typical packages include: content creation (graphics, captions, hashtag research), scheduling and posting, community management (responding to comments/DMs), and monthly analytics reports. Ad management is usually a separate add-on priced as a percentage of ad spend (10-20%)." },
  { q: "How many clients can a freelance social media manager handle?", a: "Most freelancers manage 3-6 clients simultaneously for full-time income, depending on the scope. A minimal 2-platform, 3-posts/week client might take 5-10 hours/month; a full 5-platform, daily-post client with ads could take 30-50 hours/month." },
  { q: "Should I charge per platform or per package?", a: "Charging per platform is transparent and easier to scope. Packages (basic/standard/premium) are easier to sell but harder to customize. Most experienced social media managers use a base rate plus platform add-ons to balance both approaches." },
  { q: "Is monthly retainer or project-based pricing better for social media?", a: "Monthly retainers are better for ongoing management because they provide income predictability. Project-based pricing works for one-time audits, strategy documents, or account setups. Retainers are the industry standard for ongoing social media management." },
  { q: "What should I include in a social media manager proposal?", a: "Include: scope (platforms, posts/week, content types), deliverables (captions, graphics, stories, reports), communication terms (response time, review cycles), pricing breakdown, and a 3-6 month contract clause. Always charge a one-time onboarding fee ($200-$500) to cover initial setup." },
];

const EXPANDED_FAQS = SOCIAL_EXPANDED_FAQS.socialManagerPricing;

export default function SocialMediaManagerPricingCalculator() {
  useCurrencyVersion();
  const [platforms, setPlatforms] = useState(3);
  const [postsPerWeek, setPostsPerWeek] = useState(5);
  const [includesContentCreation, setIncludesContentCreation] = useState(true);
  const [includesReporting, setIncludesReporting] = useState(true);
  const [adSpend, setAdSpend] = useState(0);

  const basePerPlatform = 250;
  const postCost = postsPerWeek * 4 * 12;
  const contentAddon = includesContentCreation ? 450 : 0;
  const reportingAddon = includesReporting ? 150 : 0;
  const adManagement = adSpend > 0 ? adSpend * 0.15 : 0;

  const total = (basePerPlatform * platforms) + postCost + contentAddon + reportingAddon + adManagement;
  const hourlyEquiv = total / (platforms * 8 + postsPerWeek * 4 * 1.5);

  return (
    <>
      <SEOHead
        title="Free Social Media Manager Pricing Calculator Online 2025 - Generate Your Monthly Quote | CalcHive"
        description="Free social media manager pricing calculator online. Generate a monthly management quote based on platforms, number of posts and ad spend instantly. 100% free for freelancers and agencies, no login needed."
        canonical="/social-media-manager-pricing-calculator"
        keywords="free social media manager pricing calculator, social media management pricing calculator free online, how much to charge for social media management, social media manager rate calculator free, social media pricing tool free, freelance social media manager pricing calculator"
        category="Social"
        schemaType="WebApplication"
        schemaApplicationCategory="CalculatorApplication"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-pink-600 dark:text-pink-400 bg-pink-50 dark:bg-pink-950/50 px-3 py-1 rounded-full mb-4">
            <Users className="w-3.5 h-3.5" /> Social
          </span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Social Media Manager Pricing Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free social media manager pricing calculator to generate monthly quotes from platforms, posts, content creation, reporting, and ad spend. This social media management pricing calculator free online helps answer how much to charge for social media management and works as a social media manager rate calculator free, social media pricing tool free, and freelance social media manager pricing calculator.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="smm-platforms" label="Number of Platforms" value={platforms} min={1} max={8} step={1} onChange={setPlatforms} format={v => `${v} platform${v === 1 ? "" : "s"}`} testId="input-platforms" helpText="Instagram, TikTok, Facebook, LinkedIn, X, Pinterest, YouTube, Threads" />
            <SliderInput id="smm-posts" label="Posts per Week (all platforms)" value={postsPerWeek} min={1} max={35} step={1} onChange={setPostsPerWeek} format={v => `${v} posts/week`} testId="input-posts" />
            <div className="flex flex-col gap-3">
              <label className="text-sm font-semibold text-foreground">Add-on Services</label>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                {[
                  { label: "Content Creation (graphics & captions)", checked: includesContentCreation, onChange: setIncludesContentCreation, price: "+$450/mo" },
                  { label: "Monthly Analytics Report", checked: includesReporting, onChange: setIncludesReporting, price: "+$150/mo" },
                ].map(({ label, checked, onChange, price }) => (
                  <label key={label} className={`flex items-center gap-3 p-4 rounded-xl border cursor-pointer transition-colors ${checked ? "border-primary/50 bg-primary/5" : "border-border bg-card hover:bg-muted/30"}`}>
                    <input type="checkbox" checked={checked} onChange={e => onChange(e.target.checked)} className="w-4 h-4 accent-primary flex-shrink-0" />
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-semibold text-foreground">{label}</p>
                      <p className="text-xs text-muted-foreground">{price}</p>
                    </div>
                  </label>
                ))}
              </div>
            </div>
            <SliderInput id="smm-adspend" label="Monthly Ad Spend Managed" value={adSpend} min={0} max={20000} step={100} onChange={setAdSpend} format={v => v === 0 ? "No ad management" : `${formatCurrencyValue(v, { maximumFractionDigits: 0 })}/mo`} testId="input-adspend" helpText="15% management fee applied to ad spend" />
          </div>
          <motion.div key={`${platforms}-${postsPerWeek}-${includesContentCreation}-${includesReporting}-${adSpend}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-pink-500 to-purple-600 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Suggested Monthly Quote</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-monthly-quote">{fmt(total)}</p>
              <p className="text-white/70 text-sm mt-1">- {fmt(hourlyEquiv)}/hr effective rate - {platforms} platform{platforms !== 1 ? "s" : ""}</p>
            </div>
            <div className="grid grid-cols-2 gap-3">
              {[
                { label: `Platform Base (${platforms} x )`, value: fmt(basePerPlatform * platforms) },
                { label: `Post Management (${postsPerWeek}/wk)`, value: fmt(postCost) },
                { label: "Content Creation", value: includesContentCreation ? fmt(contentAddon) : "Not included" },
                { label: adSpend > 0 ? `Ad Mgmt (15% of ${formatCurrencyValue(adSpend, { maximumFractionDigits: 0 })})` : "Ad Management", value: adSpend > 0 ? fmt(adManagement) : "Not included" },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-base font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How Much Should a Social Media Manager Charge Per Month</h2>
          <p className="text-muted-foreground leading-relaxed">This freelance social media manager pricing calculator builds your monthly quote from the ground up: a base management fee per platform ($250/month), a posting fee based on weekly post volume ($12/post), optional add-ons for content creation and reporting, and a 15% ad management fee on any paid ad budget. This model reflects industry-standard pricing for freelance social media management services and ensures your rates account for all time invested in client accounts.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Base = $250  x  Platforms</p>
            <p>Posts = (Posts/Week  x  4 weeks  x  $12/post)</p>
            <p>Ad Mgmt = Monthly Ad Spend  x  15%</p>
            <p>Total = Base + Posts + Add-ons + Ad Mgmt</p>
          </div>
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Social Media Management Rate for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Add the base platform cost, post volume, content creation, reporting, and ad management fee to build a monthly quote.</p>
          <h2 className="text-2xl font-bold text-foreground">Pricing by Platform Posts and Ad Spend Explained</h2>
          <p className="text-muted-foreground leading-relaxed">More platforms and posts increase production work, while ad spend often adds management responsibility and a percentage-based fee.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Social Media Manager Rate Calculator for Freelancers and Agencies</h2>
          <p className="text-muted-foreground leading-relaxed">Use the result as a starting quote for retainers, proposals, and client packages.</p>
        </section>
        <SocialExpandedContent kind="socialManagerPricing" />

        <section className="mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/social-media-manager-pricing-calculator" headingLevel="h3" />
      </main>
    </>
  );
}



